qubits = range(87)
paulis = {i: set() for i in qubits}

for s in stabs_padded:
    for i, char in enumerate(s):
        if char != 'I':
            paulis[i].add(char)

for i, s in enumerate(stabs_padded):
    if len(stabs[i]) == 87:
        indices = [k for k, char in enumerate(s) if char != 'I']
        print(f"Stabilizer {i}: indices {indices}")
        # Check Pauli on 77
        if 77 in indices:
            print(f"  Pauli on 77: {s[77]}")

